import React from 'react';
import { useNavigate } from 'react-router-dom';

interface SidebarProps {
  currentPage: string;
  setCurrentPage: (page: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentPage, setCurrentPage }) => {
  const navigate = useNavigate();

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: 'dashboard' },
    { id: 'colaboradores', label: 'Colaboradores', icon: 'group' },
    { id: 'processamento', label: 'Processamento', icon: 'account_balance_wallet' },
    { id: 'ferias', label: 'Férias', icon: 'beach_access' },
    { id: 'faltas', label: 'Faltas e Bónus', icon: 'event_busy' },
    { id: 'relatorios', label: 'Relatórios', icon: 'description' },
    { id: 'auditoria', label: 'Auditoria', icon: 'security' },
    { id: 'faturas', label: 'Faturas', icon: 'receipt_long' },
    { id: 'multicaixa', label: 'Multicaixa', icon: 'account_balance' },
    { id: 'bancario', label: 'Arquivo CNAB', icon: 'sync_alt' },
    { id: 'guias', label: 'Guias DLI/AGT', icon: 'article' },
    { id: 'mrt', label: 'Submissão MRT', icon: 'upload_file' },
    { id: 'configuracoes', label: 'Configurações', icon: 'settings' },
  ];

  const handleNavigate = (page: string) => {
    setCurrentPage(page);
    navigate(`/${page}`);
  };

  return (
    <aside className="w-64 border-r border-slate-200 dark:border-slate-800 bg-white dark:bg-background-dark flex flex-col fixed h-full">
      <div className="p-6 flex items-center gap-3">
        <div className="bg-primary text-white p-1.5 rounded-lg">
          <span className="material-symbols-outlined">payments</span>
        </div>
        <h2 className="text-xl font-bold tracking-tight text-primary">SALYA</h2>
      </div>
      
      <nav className="flex-1 px-4 space-y-1 overflow-y-auto">
        {menuItems.map((item) => (
          <button
            key={item.id}
            onClick={() => handleNavigate(item.id)}
            className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors ${
              currentPage === item.id
                ? 'bg-primary/10 text-primary font-medium'
                : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
            }`}
          >
            <span className="material-symbols-outlined">{item.icon}</span>
            {item.label}
          </button>
        ))}
      </nav>

      <div className="p-4 border-t border-slate-200 dark:border-slate-800">
        <div className="flex items-center gap-3 p-2">
          <div className="size-10 rounded-full bg-primary/20 flex items-center justify-center text-primary font-bold">
            AS
          </div>
          <div className="overflow-hidden">
            <p className="text-sm font-semibold truncate">Admin Salya</p>
            <p className="text-xs text-slate-500 truncate">admin@salya.com</p>
          </div>
        </div>
        <button 
          onClick={() => navigate('/login')}
          className="w-full mt-3 flex items-center gap-2 px-3 py-2 text-sm text-slate-500 hover:text-rose-500 transition-colors"
        >
          <span className="material-symbols-outlined text-lg">logout</span>
          Terminar Sessão
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;
